message.content:
@startuml
skinparam classAttributeIconSize 0
hide circle

class "Matrícula" {
    -cliente: Client
    -tempo: Int
    -quadra: Turma
}

class Aluno {
    -id: Int
    -nome: String
    -locaçao: List<Matrícula>
}

class controleNúmeroMatrícula {
    -quantidade: Int
}

class Curso {
    -nome: String
    -quadra: List<Turma>
}

class Turma {
    -numero: Int
    -aluguel: Matrícula
    -ginasío: Curso
}

Aluno --|> "composição 1": 
Turma ..^ controleNúmeroMatrícula : 

Curso --> "composição 1\n1..*" : Turma  
Turma *-- "composição\n1..*"\n: Matrícula  

@enduml
